export const STATIC_HTML = "<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta name=\"bormex-api-base\" content=\"https://tnajelbyzkrifukfgnxv.functions.supabase.co/bormex-crm\" />\n    <title>Ventas por anuncio</title>\n    <style>\n:root {\n  --bg: #f4f6f8;\n  --surface: #ffffff;\n  --surface-muted: #eef2f5;\n  --text: #16202a;\n  --muted: #697586;\n  --border: #d7dde5;\n  --primary: #0f766e;\n  --primary-strong: #115e59;\n  --accent: #be6a15;\n  --danger: #b42318;\n  --warning: #a15c07;\n  --success: #16803c;\n  --shadow: 0 16px 40px rgba(22, 32, 42, 0.08);\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  background: var(--bg);\n  color: var(--text);\n  font-family:\n    Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\",\n    sans-serif;\n}\n\n.auth-gate {\n  position: fixed;\n  inset: 0;\n  z-index: 20;\n  display: grid;\n  place-items: center;\n  padding: 20px;\n  background: rgba(15, 23, 32, 0.72);\n}\n\n.auth-card {\n  width: min(100%, 360px);\n  display: grid;\n  gap: 14px;\n  padding: 24px;\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  box-shadow: var(--shadow);\n}\n\n.auth-card .brand-mark {\n  margin-bottom: 2px;\n}\n\n.auth-card h2 {\n  margin: 0;\n  font-size: 22px;\n}\n\n.auth-card label {\n  display: grid;\n  gap: 6px;\n  color: var(--muted);\n  font-weight: 700;\n}\n\n.auth-card input {\n  min-height: 42px;\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  padding: 0 12px;\n  color: var(--text);\n}\n\nbutton,\ninput,\nselect,\ntextarea {\n  font: inherit;\n}\n\nbutton {\n  cursor: pointer;\n}\n\n.app-shell {\n  display: grid;\n  grid-template-columns: 260px minmax(0, 1fr);\n  min-height: 100vh;\n}\n\n.sidebar {\n  background: #17212b;\n  color: #eef4f8;\n  display: flex;\n  flex-direction: column;\n  padding: 22px;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  min-height: 48px;\n}\n\n.brand-mark {\n  display: grid;\n  place-items: center;\n  width: 42px;\n  height: 42px;\n  border-radius: 8px;\n  background: #0f766e;\n  color: #ffffff;\n  font-weight: 800;\n}\n\n.brand strong,\n.brand span {\n  display: block;\n}\n\n.brand span:not(.brand-mark) {\n  color: #aeb9c5;\n  font-size: 13px;\n}\n\n.nav {\n  display: grid;\n  gap: 6px;\n  margin-top: 34px;\n}\n\n.nav-item {\n  border: 0;\n  border-radius: 8px;\n  background: transparent;\n  color: #c8d2dc;\n  padding: 11px 12px;\n  text-align: left;\n}\n\n.nav-item:hover,\n.nav-item.active {\n  background: #263342;\n  color: #ffffff;\n}\n\n.sidebar-footer {\n  margin-top: auto;\n  display: grid;\n  gap: 10px;\n  color: #aeb9c5;\n  font-size: 13px;\n}\n\n.main {\n  min-width: 0;\n  padding: 28px;\n}\n\n.topbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  margin-bottom: 24px;\n}\n\n.eyebrow {\n  margin: 0 0 4px;\n  color: var(--muted);\n  font-size: 13px;\n  font-weight: 700;\n  text-transform: uppercase;\n}\n\nh1,\nh2,\np {\n  margin-top: 0;\n}\n\nh1 {\n  margin-bottom: 0;\n  font-size: 30px;\n}\n\nh2 {\n  margin-bottom: 4px;\n  font-size: 18px;\n}\n\n.topbar-actions,\n.form-actions {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  flex-wrap: wrap;\n}\n\n.table-actions {\n  align-items: center;\n  display: flex;\n  gap: 8px;\n}\n\n.primary-button,\n.secondary-button,\n.ghost-button,\n.danger-button {\n  border: 1px solid transparent;\n  border-radius: 8px;\n  min-height: 40px;\n  padding: 0 14px;\n  font-weight: 700;\n}\n\n.primary-button {\n  background: var(--primary);\n  color: #ffffff;\n}\n\n.primary-button:hover {\n  background: var(--primary-strong);\n}\n\n.secondary-button {\n  background: var(--surface);\n  border-color: var(--border);\n  color: var(--text);\n}\n\n.compact {\n  margin-top: 12px;\n  min-height: 34px;\n}\n\n.ghost-button {\n  background: transparent;\n  border-color: #405164;\n  color: #eef4f8;\n}\n\n.danger-button {\n  background: #fff5f4;\n  border-color: #f4c7c3;\n  color: var(--danger);\n}\n\n.view {\n  display: none;\n}\n\n.view.active {\n  display: grid;\n  gap: 18px;\n}\n\n.metric-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));\n  gap: 14px;\n}\n\n.metric,\n.panel {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  box-shadow: var(--shadow);\n}\n\n.metric {\n  padding: 18px;\n}\n\n.metric span {\n  display: block;\n  color: var(--muted);\n  font-size: 13px;\n  font-weight: 700;\n}\n\n.metric strong {\n  display: block;\n  margin-top: 8px;\n  font-size: 26px;\n}\n\n.content-grid {\n  display: grid;\n  grid-template-columns: minmax(0, 1.6fr) minmax(320px, 0.8fr);\n  gap: 18px;\n}\n\n.panel {\n  min-width: 0;\n  padding: 18px;\n}\n\n.panel.wide {\n  min-width: 0;\n}\n\n.panel-header {\n  display: flex;\n  align-items: start;\n  justify-content: space-between;\n  gap: 14px;\n  margin-bottom: 14px;\n}\n\n.panel-header p {\n  margin-bottom: 0;\n  color: var(--muted);\n  font-size: 14px;\n}\n\n.table-wrap {\n  overflow-x: auto;\n}\n\ntable {\n  border-collapse: collapse;\n  width: 100%;\n  min-width: 760px;\n}\n\nth,\ntd {\n  border-bottom: 1px solid var(--border);\n  padding: 11px 10px;\n  text-align: left;\n  vertical-align: middle;\n  white-space: nowrap;\n}\n\nth {\n  color: var(--muted);\n  font-size: 12px;\n  text-transform: uppercase;\n}\n\ntd {\n  font-size: 14px;\n}\n\n.empty {\n  padding: 24px;\n  color: var(--muted);\n  text-align: center;\n}\n\n.badge {\n  display: inline-flex;\n  align-items: center;\n  border-radius: 999px;\n  padding: 4px 8px;\n  font-size: 12px;\n  font-weight: 800;\n}\n\n.badge.scale {\n  background: #e8f7ee;\n  color: var(--success);\n}\n\n.badge.hold {\n  background: #eef2f5;\n  color: #455468;\n}\n\n.badge.reduce {\n  background: #fff2dd;\n  color: var(--warning);\n}\n\n.badge.pause {\n  background: #fff0ee;\n  color: var(--danger);\n}\n\n.form-grid,\n.import-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(170px, 1fr));\n  gap: 14px;\n}\n\nlabel {\n  display: grid;\n  gap: 7px;\n  color: var(--muted);\n  font-size: 13px;\n  font-weight: 700;\n}\n\ninput,\nselect,\ntextarea {\n  width: 100%;\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  background: #ffffff;\n  color: var(--text);\n  min-height: 42px;\n  padding: 9px 11px;\n}\n\ntextarea {\n  min-height: 86px;\n  resize: vertical;\n}\n\ninput:focus,\nselect:focus,\ntextarea:focus {\n  border-color: var(--primary);\n  outline: 3px solid rgba(15, 118, 110, 0.18);\n}\n\n.checkbox-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(130px, 1fr));\n  gap: 8px;\n}\n\n.check-option {\n  align-items: center;\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  color: var(--text);\n  display: flex;\n  flex-direction: row;\n  font-weight: 700;\n  gap: 8px;\n  min-height: 42px;\n  padding: 8px 10px;\n}\n\n.check-option input {\n  accent-color: var(--primary);\n  min-height: 18px;\n  width: 18px;\n}\n\n.connection-panel {\n  align-items: flex-start;\n  background: var(--surface-muted);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  display: flex;\n  gap: 12px;\n  padding: 14px;\n}\n\n.connection-panel strong {\n  display: block;\n  margin-bottom: 4px;\n}\n\n.connection-panel p {\n  color: var(--muted);\n  font-size: 14px;\n  line-height: 1.5;\n  margin-bottom: 0;\n}\n\n.connection-dot {\n  border-radius: 999px;\n  flex: 0 0 auto;\n  height: 10px;\n  margin-top: 5px;\n  width: 10px;\n}\n\n.connection-dot.pending {\n  background: var(--warning);\n}\n\n.connection-dot.connected {\n  background: var(--success);\n}\n\n.full {\n  grid-column: 1 / -1;\n}\n\n.activity-list {\n  display: grid;\n  gap: 10px;\n}\n\n.activity-item {\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  padding: 12px;\n}\n\n.activity-item strong,\n.activity-item span {\n  display: block;\n}\n\n.activity-item span {\n  color: var(--muted);\n  font-size: 13px;\n  margin-top: 4px;\n}\n\n.crm-shell {\n  display: grid;\n  grid-template-columns: minmax(280px, 0.35fr) minmax(0, 1fr);\n  gap: 18px;\n  min-height: calc(100vh - 150px);\n}\n\n.crm-list-panel,\n.crm-thread-panel {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  box-shadow: var(--shadow);\n  min-width: 0;\n  padding: 18px;\n}\n\n.crm-list-panel {\n  display: grid;\n  grid-template-rows: auto minmax(0, 1fr);\n}\n\n.conversation-list {\n  display: grid;\n  align-content: start;\n  gap: 8px;\n  overflow-y: auto;\n}\n\n.conversation-item {\n  background: #ffffff;\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  color: var(--text);\n  display: grid;\n  gap: 5px;\n  min-height: 82px;\n  padding: 11px;\n  text-align: left;\n}\n\n.conversation-item.active,\n.conversation-item:hover {\n  border-color: var(--primary);\n  box-shadow: 0 0 0 3px rgba(15, 118, 110, 0.12);\n}\n\n.conversation-item strong,\n.conversation-item small {\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.conversation-item small {\n  color: var(--muted);\n}\n\n.conversation-item .conversation-attribution {\n  color: var(--primary);\n  font-weight: 800;\n}\n\n.channel-pill {\n  border-radius: 999px;\n  display: inline-flex;\n  font-size: 11px;\n  font-weight: 800;\n  justify-self: start;\n  padding: 3px 7px;\n}\n\n.channel-pill.whatsapp {\n  background: #e8f7ee;\n  color: #16803c;\n}\n\n.channel-pill.messenger {\n  background: #eaf2ff;\n  color: #2563eb;\n}\n\n.channel-pill.instagram {\n  background: #fff0f5;\n  color: #be185d;\n}\n\n.crm-thread-panel {\n  display: grid;\n  grid-template-rows: auto minmax(280px, 1fr) auto;\n  gap: 14px;\n}\n\n.thread-header {\n  border-bottom: 1px solid var(--border);\n  padding-bottom: 12px;\n}\n\n.thread-header p {\n  color: var(--muted);\n  font-size: 14px;\n  margin-bottom: 0;\n}\n\n.message-thread {\n  align-content: end;\n  background: var(--surface-muted);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  display: grid;\n  gap: 10px;\n  overflow-y: auto;\n  padding: 14px;\n}\n\n.message-bubble {\n  border-radius: 8px;\n  max-width: min(680px, 82%);\n  padding: 10px 12px;\n}\n\n.message-bubble.inbound {\n  background: #ffffff;\n  border: 1px solid var(--border);\n  justify-self: start;\n}\n\n.message-bubble.outbound {\n  background: var(--primary);\n  color: #ffffff;\n  justify-self: end;\n}\n\n.message-bubble p {\n  margin-bottom: 5px;\n  white-space: pre-wrap;\n}\n\n.message-bubble span {\n  display: block;\n  font-size: 11px;\n  opacity: 0.72;\n}\n\n.message-bubble small {\n  display: block;\n  font-size: 11px;\n  font-weight: 800;\n  margin-bottom: 4px;\n  opacity: 0.78;\n}\n\n.reply-box {\n  align-items: end;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  gap: 10px;\n}\n\n.reply-box.disabled {\n  opacity: 0.55;\n  pointer-events: none;\n}\n\n.hint {\n  margin-top: 16px;\n  border-radius: 8px;\n  background: var(--surface-muted);\n  color: #455468;\n  font-size: 13px;\n  line-height: 1.7;\n  padding: 12px;\n}\n\n.rules-form {\n  display: grid;\n  gap: 14px;\n}\n\n.toast {\n  position: fixed;\n  right: 22px;\n  bottom: 22px;\n  max-width: 360px;\n  border-radius: 8px;\n  background: #17212b;\n  color: #ffffff;\n  opacity: 0;\n  pointer-events: none;\n  padding: 12px 14px;\n  transform: translateY(10px);\n  transition:\n    opacity 180ms ease,\n    transform 180ms ease;\n}\n\n.toast.show {\n  opacity: 1;\n  transform: translateY(0);\n}\n\n@media (max-width: 980px) {\n  .app-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .sidebar {\n    position: sticky;\n    top: 0;\n    z-index: 5;\n    padding: 14px;\n  }\n\n  .brand,\n  .sidebar-footer {\n    display: none;\n  }\n\n  .nav {\n    display: flex;\n    gap: 8px;\n    margin-top: 0;\n    overflow-x: auto;\n  }\n\n  .nav-item {\n    flex: 0 0 auto;\n  }\n\n  .main {\n    padding: 18px;\n  }\n\n  .topbar,\n  .panel-header {\n    align-items: stretch;\n    flex-direction: column;\n  }\n\n  .metric-grid,\n  .content-grid,\n  .crm-shell,\n  .form-grid,\n  .import-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .crm-shell {\n    min-height: auto;\n  }\n\n  .reply-box {\n    grid-template-columns: 1fr;\n  }\n\n  h1 {\n    font-size: 26px;\n  }\n}\n\n</style>\n  </head>\n  <body>\n    <div class=\"app-shell\">\n      <aside class=\"sidebar\">\n        <div class=\"brand\">\n          <span class=\"brand-mark\">VA</span>\n          <div>\n            <strong>Ventas Ads</strong>\n            <span>WhatsApp + Meta</span>\n          </div>\n        </div>\n\n        <nav class=\"nav\" aria-label=\"Secciones\">\n          <button class=\"nav-item active\" data-view=\"dashboard\">Panel</button>\n          <button class=\"nav-item\" data-view=\"crm\">CRM</button>\n          <button class=\"nav-item\" data-view=\"sales\">Ventas</button>\n          <button class=\"nav-item\" data-view=\"leads\">Leads</button>\n          <button class=\"nav-item\" data-view=\"ads\">Anuncios</button>\n          <button class=\"nav-item\" data-view=\"settings\">Datos</button>\n        </nav>\n\n        <div class=\"sidebar-footer\">\n          <span id=\"storageStatus\">Guardado local</span>\n          <button class=\"ghost-button\" id=\"clearDemoData\" type=\"button\">Reiniciar datos</button>\n        </div>\n      </aside>\n\n      <main class=\"main\">\n        <header class=\"topbar\">\n          <div>\n            <p class=\"eyebrow\">Seguimiento comercial</p>\n            <h1 id=\"viewTitle\">Panel</h1>\n          </div>\n          <div class=\"topbar-actions\">\n            <button class=\"secondary-button\" id=\"exportJson\" type=\"button\">Exportar JSON</button>\n            <button class=\"primary-button\" data-open-sale type=\"button\">Registrar venta</button>\n          </div>\n        </header>\n\n        <section class=\"view active\" id=\"dashboardView\">\n          <div class=\"metric-grid\">\n            <article class=\"metric\">\n              <span>Gasto</span>\n              <strong id=\"metricSpend\">$0</strong>\n            </article>\n            <article class=\"metric\">\n              <span>Ingresos</span>\n              <strong id=\"metricRevenue\">$0</strong>\n            </article>\n            <article class=\"metric\">\n              <span>Mensajes</span>\n              <strong id=\"metricMessages\">0</strong>\n            </article>\n            <article class=\"metric\">\n              <span>Costo mensaje</span>\n              <strong id=\"metricCostPerMessage\">$0</strong>\n            </article>\n            <article class=\"metric\">\n              <span>ROAS</span>\n              <strong id=\"metricRoas\">0.00x</strong>\n            </article>\n            <article class=\"metric\">\n              <span>Costo por venta</span>\n              <strong id=\"metricCpa\">$0</strong>\n            </article>\n          </div>\n\n          <div class=\"content-grid\">\n            <section class=\"panel wide\">\n              <div class=\"panel-header\">\n                <div>\n                  <h2>Rendimiento por anuncio</h2>\n                  <p>Mensajes de Meta y ventas atribuidas por número de WhatsApp.</p>\n                </div>\n                <select id=\"statusFilter\" aria-label=\"Filtro de recomendación\">\n                  <option value=\"all\">Todos</option>\n                  <option value=\"scale\">Subir</option>\n                  <option value=\"hold\">Mantener</option>\n                  <option value=\"reduce\">Bajar</option>\n                  <option value=\"pause\">Pausar</option>\n                </select>\n              </div>\n              <div class=\"table-wrap\">\n                <table>\n                  <thead>\n                    <tr>\n                      <th>Anuncio</th>\n                      <th>Campaña</th>\n                      <th>Gasto</th>\n                      <th>Mensajes Meta</th>\n                      <th>Ventas</th>\n                      <th>Ingresos</th>\n                      <th>Costo mensaje</th>\n                      <th>Costo venta</th>\n                      <th>ROAS</th>\n                      <th>Acción</th>\n                    </tr>\n                  </thead>\n                  <tbody id=\"adsPerformanceTable\"></tbody>\n                </table>\n              </div>\n            </section>\n\n            <section class=\"panel\">\n              <div class=\"panel-header\">\n                <div>\n                  <h2>Ventas recientes</h2>\n                  <p>Últimos cierres registrados.</p>\n                </div>\n              </div>\n              <div class=\"activity-list\" id=\"recentSales\"></div>\n            </section>\n          </div>\n        </section>\n\n        <section class=\"view\" id=\"crmView\">\n          <section class=\"crm-shell\">\n            <div class=\"crm-list-panel\">\n              <div class=\"panel-header\">\n                <div>\n                  <h2>Inbox</h2>\n                  <p>WhatsApp, Messenger e Instagram.</p>\n                </div>\n                <select id=\"crmChannelFilter\" aria-label=\"Canal\">\n                  <option value=\"all\">Todos</option>\n                  <option value=\"whatsapp\">WhatsApp</option>\n                  <option value=\"messenger\">Messenger</option>\n                  <option value=\"instagram\">Instagram</option>\n                </select>\n              </div>\n              <div class=\"conversation-list\" id=\"conversationList\"></div>\n            </div>\n\n            <div class=\"crm-thread-panel\">\n              <div class=\"thread-header\" id=\"threadHeader\">\n                <div>\n                  <h2>Selecciona una conversación</h2>\n                  <p>Los mensajes nuevos aparecerán aquí cuando llegue el webhook.</p>\n                </div>\n              </div>\n              <div class=\"message-thread\" id=\"messageThread\"></div>\n              <form class=\"reply-box\" id=\"replyForm\">\n                <textarea name=\"text\" rows=\"2\" placeholder=\"Escribe una respuesta\"></textarea>\n                <button class=\"primary-button\" type=\"submit\">Enviar</button>\n              </form>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"view\" id=\"salesView\">\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Registrar venta</h2>\n                <p>El número se normaliza para buscar el anuncio original.</p>\n              </div>\n            </div>\n            <form class=\"form-grid\" id=\"saleForm\">\n              <label>\n                Número de WhatsApp\n                <input name=\"phone\" autocomplete=\"tel\" placeholder=\"+52 999 123 4567\" required />\n              </label>\n              <label class=\"full\">\n                Productos vendidos\n                <div class=\"checkbox-grid\">\n                  <label class=\"check-option\">\n                    <input name=\"products\" type=\"checkbox\" value=\"Imán\" />\n                    <span>Imán</span>\n                  </label>\n                  <label class=\"check-option\">\n                    <input name=\"products\" type=\"checkbox\" value=\"Pin\" />\n                    <span>Pin</span>\n                  </label>\n                  <label class=\"check-option\">\n                    <input name=\"products\" type=\"checkbox\" value=\"Llavero\" />\n                    <span>Llavero</span>\n                  </label>\n                  <label class=\"check-option\">\n                    <input name=\"products\" type=\"checkbox\" value=\"Termoadherible\" />\n                    <span>Termoadherible</span>\n                  </label>\n                </div>\n              </label>\n              <label>\n                Monto vendido\n                <input name=\"amount\" inputmode=\"decimal\" placeholder=\"2500\" required />\n              </label>\n              <label>\n                Fecha\n                <input name=\"date\" type=\"date\" required />\n              </label>\n              <label class=\"full\">\n                ID del anuncio\n                <input name=\"adId\" list=\"adIdOptions\" placeholder=\"Pega el ad_id de Business Suite\" />\n                <datalist id=\"adIdOptions\"></datalist>\n              </label>\n              <div class=\"form-actions full\">\n                <button class=\"primary-button\" type=\"submit\">Guardar venta</button>\n                <button class=\"secondary-button\" id=\"fillSaleExample\" type=\"button\">Ejemplo</button>\n              </div>\n            </form>\n          </section>\n\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Historial de ventas</h2>\n                <p>Coincidencia automática por número.</p>\n              </div>\n              <button class=\"secondary-button\" id=\"exportSalesCsv\" type=\"button\">Exportar CSV</button>\n            </div>\n            <div class=\"table-wrap\">\n              <table>\n                <thead>\n                  <tr>\n                    <th>Fecha</th>\n                    <th>Número</th>\n                    <th>Producto</th>\n                    <th>Monto</th>\n                    <th>ID anuncio</th>\n                    <th>Anuncio atribuido</th>\n                    <th></th>\n                  </tr>\n                </thead>\n                <tbody id=\"salesTable\"></tbody>\n              </table>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"view\" id=\"leadsView\">\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Leads de WhatsApp</h2>\n                <p>Contactos reales detectados desde WhatsApp Cloud API.</p>\n              </div>\n            </div>\n            <div class=\"connection-panel\">\n              <span class=\"connection-dot pending\"></span>\n              <div>\n                <strong>Conexión pendiente</strong>\n                <p id=\"whatsappConnectionText\">Los conteos por anuncio vienen de Meta Ads; aquí aparecerán los contactos con número cuando WhatsApp entregue el webhook real.</p>\n              </div>\n            </div>\n          </section>\n\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Leads registrados</h2>\n                <p>Base automática con número usada para atribuir ventas.</p>\n              </div>\n              <button class=\"secondary-button\" id=\"exportLeadsCsv\" type=\"button\">Exportar CSV</button>\n            </div>\n            <div class=\"table-wrap\">\n              <table>\n                <thead>\n                  <tr>\n                    <th>Fecha</th>\n                    <th>Número</th>\n                    <th>Campaña</th>\n                    <th>Anuncio</th>\n                    <th>ID</th>\n                    <th></th>\n                  </tr>\n                </thead>\n                <tbody id=\"leadsTable\"></tbody>\n              </table>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"view\" id=\"adsView\">\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Gasto por anuncio</h2>\n                <p>Se detectará automáticamente desde Meta Ads API.</p>\n              </div>\n            </div>\n            <div class=\"connection-panel\">\n              <span class=\"connection-dot pending\"></span>\n              <div>\n                <strong>Conexión pendiente</strong>\n                <p id=\"adsConnectionText\">Cuando conectemos Meta Ads API, aquí aparecerán solo anuncios activos con gasto, presupuesto, campaña y métricas de mensajes.</p>\n                <button class=\"secondary-button compact\" id=\"syncAds\" type=\"button\">Sincronizar anuncios activos</button>\n              </div>\n            </div>\n          </section>\n\n          <section class=\"panel\">\n            <div class=\"panel-header\">\n              <div>\n                <h2>Registros de gasto</h2>\n                <p>Resumen automático de inversión por anuncio activo.</p>\n              </div>\n              <button class=\"secondary-button\" id=\"exportSpendCsv\" type=\"button\">Exportar CSV</button>\n            </div>\n            <div class=\"table-wrap\">\n              <table>\n                <thead>\n                  <tr>\n                    <th>Fecha</th>\n                    <th>Campaña</th>\n                    <th>Anuncio</th>\n                    <th>ID anuncio</th>\n                    <th>Gasto</th>\n                    <th>Presupuesto</th>\n                    <th></th>\n                  </tr>\n                </thead>\n                <tbody id=\"spendTable\"></tbody>\n              </table>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"view\" id=\"settingsView\">\n          <div class=\"content-grid\">\n            <section class=\"panel\">\n              <div class=\"panel-header\">\n                <div>\n                  <h2>Importar datos</h2>\n                  <p>Formato CSV simple para migrar o respaldar.</p>\n                </div>\n              </div>\n              <div class=\"import-grid\">\n                <label>\n                  Tipo de datos\n                  <select id=\"importType\">\n                    <option value=\"sales\">Ventas</option>\n                    <option value=\"leads\">Leads</option>\n                    <option value=\"spend\">Gasto</option>\n                  </select>\n                </label>\n                <label>\n                  Archivo CSV\n                  <input id=\"csvInput\" type=\"file\" accept=\".csv,text/csv\" />\n                </label>\n                <button class=\"primary-button\" id=\"importCsv\" type=\"button\">Importar CSV</button>\n              </div>\n              <div class=\"hint\">\n                Ventas: phone,product,amount,date,adId<br />\n                Leads: phone,campaign,adset,ad,adId,date,message<br />\n                Gasto: campaign,ad,adId,spend,dailyBudget,date\n              </div>\n            </section>\n\n            <section class=\"panel\">\n              <div class=\"panel-header\">\n                <div>\n                  <h2>Reglas de decisión</h2>\n                  <p>Usadas para sugerir subir, bajar o pausar.</p>\n                </div>\n              </div>\n              <form class=\"rules-form\" id=\"rulesForm\">\n                <label>\n                  Costo por venta ideal\n                  <input name=\"targetCpa\" inputmode=\"decimal\" />\n                </label>\n                <label>\n                  ROAS mínimo\n                  <input name=\"minRoas\" inputmode=\"decimal\" />\n                </label>\n                <label>\n                  Mínimo de mensajes para decidir\n                  <input name=\"minLeads\" inputmode=\"numeric\" />\n                </label>\n                <button class=\"primary-button\" type=\"submit\">Guardar reglas</button>\n              </form>\n            </section>\n          </div>\n        </section>\n      </main>\n    </div>\n\n    <div class=\"toast\" id=\"toast\" role=\"status\" aria-live=\"polite\"></div>\n    <script>\nconst STORAGE_KEY = \"ventas_ads_state_v1\";\nconst AUTH_STORAGE_KEY = \"ventas_ads_panel_code_v1\";\nconst API_BASE = getApiBase();\nlet panelCode = localStorage.getItem(AUTH_STORAGE_KEY) || \"\";\n\nconst defaultState = {\n  conversations: [],\n  messages: [],\n  sales: [],\n  leads: [],\n  spend: [],\n  ads: [],\n  rules: {\n    targetCpa: 600,\n    minRoas: 2,\n    minLeads: 8,\n  },\n};\n\nlet state = loadState();\nlet serverAvailable = false;\nlet activeConversationId = \"\";\n\nconst money = new Intl.NumberFormat(\"es-MX\", {\n  style: \"currency\",\n  currency: \"MXN\",\n  maximumFractionDigits: 0,\n});\n\nconst numberFormat = new Intl.NumberFormat(\"es-MX\", {\n  maximumFractionDigits: 2,\n});\n\nconst today = () => new Date().toISOString().slice(0, 10);\n\nfunction uid(prefix) {\n  return `${prefix}_${Date.now()}_${Math.random().toString(16).slice(2)}`;\n}\n\nfunction loadState() {\n  try {\n    const saved = localStorage.getItem(STORAGE_KEY);\n    if (!saved) return structuredClone(defaultState);\n    return { ...structuredClone(defaultState), ...JSON.parse(saved) };\n  } catch {\n    return structuredClone(defaultState);\n  }\n}\n\nfunction saveState() {\n  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));\n  document.getElementById(\"storageStatus\").textContent = `Guardado ${new Date().toLocaleTimeString(\"es-MX\", {\n    hour: \"2-digit\",\n    minute: \"2-digit\",\n  })}`;\n}\n\nasync function api(path, options = {}) {\n  const headers = {\n    \"content-type\": \"application/json\",\n    ...(options.headers || {}),\n  };\n  if (panelCode) {\n    headers.Authorization = `Basic ${btoa(`panel:${panelCode}`)}`;\n  }\n\n  const response = await fetch(`${API_BASE}${path}`, {\n    ...options,\n    headers,\n  });\n  const contentType = response.headers.get(\"content-type\") || \"\";\n  const payload = contentType.includes(\"application/json\")\n    ? await response.json()\n    : { error: await response.text() };\n  if (response.status === 401) {\n    panelCode = \"\";\n    localStorage.removeItem(AUTH_STORAGE_KEY);\n    showAuthGate();\n    throw new Error(\"Ingresa el código del panel\");\n  }\n  if (!response.ok) throw new Error(payload.error || \"No se pudo conectar\");\n  hideAuthGate();\n  return payload;\n}\n\nfunction getApiBase() {\n  const configured = document.querySelector('meta[name=\"bormex-api-base\"]')?.content?.trim() || window.BORMEX_API_BASE || \"\";\n  if (configured) return configured.replace(/\\/$/, \"\");\n  const firstPathPart = window.location.pathname.split(\"/\").filter(Boolean)[0];\n  return firstPathPart === \"bormex-crm\" ? \"/bormex-crm\" : \"\";\n}\n\nfunction showAuthGate() {\n  if (document.getElementById(\"authGate\")) return;\n  const gate = document.createElement(\"div\");\n  gate.className = \"auth-gate\";\n  gate.id = \"authGate\";\n  gate.innerHTML = `\n    <form class=\"auth-card\" id=\"authForm\">\n      <span class=\"brand-mark\">VA</span>\n      <h2>Acceso al panel</h2>\n      <label>\n        Código\n        <input name=\"code\" inputmode=\"numeric\" autocomplete=\"current-password\" required autofocus />\n      </label>\n      <button class=\"primary-button\" type=\"submit\">Entrar</button>\n    </form>\n  `;\n  document.body.appendChild(gate);\n  document.getElementById(\"authForm\").addEventListener(\"submit\", async (event) => {\n    event.preventDefault();\n    panelCode = event.currentTarget.elements.code.value.trim();\n    localStorage.setItem(AUTH_STORAGE_KEY, panelCode);\n    hideAuthGate();\n    await syncFromServer();\n    render();\n  });\n}\n\nfunction hideAuthGate() {\n  document.getElementById(\"authGate\")?.remove();\n}\n\nasync function syncFromServer() {\n  try {\n    const [config, remoteState] = await Promise.all([api(\"/api/config\"), api(\"/api/state\")]);\n    serverAvailable = true;\n    state.conversations = remoteState.conversations || state.conversations;\n    state.messages = remoteState.messages || state.messages;\n    state.sales = remoteState.sales || state.sales;\n    state.leads = remoteState.leads || state.leads;\n    state.spend = remoteState.spend || state.spend;\n    state.ads = remoteState.ads || state.ads;\n    state.rules = remoteState.rules || state.rules;\n    renderConnectionStatus(config, remoteState);\n    saveState();\n  } catch {\n    serverAvailable = false;\n    renderConnectionStatus(null, null);\n  }\n}\n\nfunction renderConnectionStatus(config, remoteState) {\n  const dots = document.querySelectorAll(\".connection-dot\");\n  const whatsappText = document.getElementById(\"whatsappConnectionText\");\n  const adsText = document.getElementById(\"adsConnectionText\");\n  const syncButton = document.getElementById(\"syncAds\");\n\n  dots.forEach((dot) => dot.classList.remove(\"connected\"));\n  if (!serverAvailable) {\n    whatsappText.textContent = \"No pude conectar con el backend. Revisa internet o intenta recargar el panel.\";\n    adsText.textContent = \"No pude conectar con el backend para sincronizar anuncios activos desde Meta Ads API.\";\n    syncButton.disabled = true;\n    return;\n  }\n\n  syncButton.disabled = !config.metaAdsConfigured;\n  if (config.whatsappWebhookConfigured) {\n    dots[0].classList.add(\"connected\");\n    const phoneStatus = config.whatsappPhoneConfigured ? \"Número real configurado.\" : \"Falta WHATSAPP_PHONE_NUMBER_ID para responder desde el CRM.\";\n    whatsappText.textContent = `Webhook guardado. ${phoneStatus} Último evento recibido: ${remoteState.lastWebhookAt || \"todavía ninguno\"}. Los contactos aparecerán cuando Meta entregue mensajes reales de producción.`;\n  } else {\n    whatsappText.textContent = \"Falta WHATSAPP_VERIFY_TOKEN en .env para verificar el webhook de Meta.\";\n  }\n\n  if (config.metaAdsConfigured) {\n    dots[1].classList.add(\"connected\");\n    adsText.textContent = `Meta Ads configurado. Última sincronización: ${remoteState.lastAdsSync || \"todavía ninguna\"}. Auto-sync cada ${config.adsSyncIntervalMinutes || 15} minutos.`;\n  } else {\n    adsText.textContent = \"Faltan META_ACCESS_TOKEN y META_AD_ACCOUNT_ID en .env para leer anuncios activos.\";\n  }\n}\n\nasync function syncAdsFromMeta() {\n  const button = document.getElementById(\"syncAds\");\n  button.disabled = true;\n  button.textContent = \"Sincronizando...\";\n  try {\n    const remoteState = await api(\"/api/sync/ads\", { method: \"POST\", body: \"{}\" });\n    state.spend = remoteState.spend || [];\n    state.ads = remoteState.ads || [];\n    saveState();\n    render();\n    await syncFromServer();\n    toast(\"Anuncios activos sincronizados\");\n  } catch (error) {\n    toast(error.message);\n  } finally {\n    button.textContent = \"Sincronizar anuncios activos\";\n    button.disabled = false;\n  }\n}\n\nfunction normalizePhone(value) {\n  const digits = String(value || \"\").replace(/\\D/g, \"\");\n  if (!digits) return \"\";\n  if (digits.length === 10) return `52${digits}`;\n  if (digits.length === 11 && digits.startsWith(\"1\")) return `52${digits.slice(1)}`;\n  if (digits.length >= 13 && digits.startsWith(\"521\")) return `52${digits.slice(3)}`;\n  return digits;\n}\n\nfunction parseMoney(value) {\n  const cleaned = String(value || \"\").replace(/[$,\\s]/g, \"\");\n  const parsed = Number(cleaned);\n  return Number.isFinite(parsed) ? parsed : 0;\n}\n\nfunction normalizeAdId(value) {\n  const text = String(value || \"\").trim();\n  if (!text) return \"\";\n  const numeric = text.match(/(?:ad[_\\s-]?id|source[_\\s-]?id)?\\D*(\\d{8,})/i);\n  if (numeric) return numeric[1];\n  return text.replace(/^ad[_\\s-]?id[:\\s-]*/i, \"\").trim();\n}\n\nfunction getSaleProducts(sale) {\n  if (Array.isArray(sale.products) && sale.products.length) return sale.products;\n  if (sale.product) return [sale.product];\n  return [];\n}\n\nfunction adKey(record) {\n  return record.adId?.trim() || `${record.campaign || \"Sin campaña\"}::${record.ad || \"Sin anuncio\"}`;\n}\n\nfunction findLeadForSale(sale) {\n  return findLeadForPhone(sale.phone);\n}\n\nfunction findAdById(adIdValue) {\n  const adId = normalizeAdId(adIdValue);\n  if (!adId) return null;\n  return (\n    (state.ads || []).find((ad) => normalizeAdId(ad.id) === adId || normalizeAdId(ad.adId) === adId) ||\n    (state.spend || []).find((spend) => normalizeAdId(spend.adId) === adId) ||\n    null\n  );\n}\n\nfunction adName(record) {\n  return record?.name || record?.ad || \"\";\n}\n\nfunction getSaleAttribution(sale) {\n  const saleAdId = normalizeAdId(sale.adId || sale.ad_id || sale.metaAdId);\n  if (saleAdId) {\n    const matchedAd = findAdById(saleAdId);\n    return {\n      source: \"manual_ad_id\",\n      campaign: sale.campaign || matchedAd?.campaign || \"ID manual\",\n      adset: sale.adset || matchedAd?.adset || \"\",\n      ad: sale.ad || adName(matchedAd) || `Anuncio ${saleAdId}`,\n      adId: saleAdId,\n    };\n  }\n  const lead = findLeadForSale(sale);\n  return lead ? { ...lead, source: \"lead\" } : null;\n}\n\nfunction findLeadForPhone(phoneValue) {\n  const phone = normalizePhone(phoneValue);\n  return [...state.leads]\n    .filter((lead) => normalizePhone(lead.phone) === phone)\n    .sort((a, b) => new Date(b.date) - new Date(a.date))[0];\n}\n\nfunction getPerformance() {\n  const map = new Map();\n  const liveAdKeys = new Set();\n\n  for (const ad of state.ads || []) {\n    const key = ad.id || `${ad.campaign || \"Sin campaña\"}::${ad.name || \"Sin anuncio\"}`;\n    liveAdKeys.add(key);\n    const metaMessages = Number(ad.messages || 0);\n    map.set(key, {\n      key,\n      campaign: ad.campaign || \"Sin campaña\",\n      ad: ad.name || \"Sin anuncio\",\n      adId: ad.id || \"\",\n      leads: 0,\n      trackedLeads: 0,\n      messages: metaMessages,\n      sales: 0,\n      revenue: 0,\n      spend: Number(ad.spend || 0),\n      dailyBudget: Number(ad.dailyBudget || 0),\n    });\n  }\n\n  for (const lead of state.leads) {\n    const key = adKey(lead);\n    if (!map.has(key)) {\n      map.set(key, {\n        key,\n        campaign: lead.campaign || \"Sin campaña\",\n        ad: lead.ad || \"Sin anuncio\",\n        adId: lead.adId || \"\",\n        leads: 0,\n        trackedLeads: 0,\n        messages: 0,\n        sales: 0,\n        revenue: 0,\n        spend: 0,\n        dailyBudget: 0,\n      });\n    }\n    const row = map.get(key);\n    row.leads += 1;\n    row.trackedLeads += 1;\n    row.messages = Math.max(Number(row.messages || 0), row.trackedLeads);\n  }\n\n  for (const spend of state.spend) {\n    const key = adKey(spend);\n    if (!map.has(key)) {\n      map.set(key, {\n        key,\n        campaign: spend.campaign || \"Sin campaña\",\n        ad: spend.ad || \"Sin anuncio\",\n        adId: spend.adId || \"\",\n        leads: 0,\n        trackedLeads: 0,\n        messages: 0,\n        sales: 0,\n        revenue: 0,\n        spend: 0,\n        dailyBudget: 0,\n      });\n    }\n    const row = map.get(key);\n    row.spend = liveAdKeys.has(key)\n      ? Math.max(Number(row.spend || 0), Number(spend.spend || 0))\n      : Number(row.spend || 0) + Number(spend.spend || 0);\n    row.dailyBudget = Math.max(row.dailyBudget, Number(spend.dailyBudget || 0));\n  }\n\n  for (const sale of state.sales) {\n    const attribution = getSaleAttribution(sale);\n    if (!attribution) continue;\n    const key = adKey(attribution);\n    if (!map.has(key)) {\n      map.set(key, {\n        key,\n        campaign: attribution.campaign || \"Sin campaña\",\n        ad: attribution.ad || \"Sin anuncio\",\n        adId: attribution.adId || \"\",\n        leads: 0,\n        trackedLeads: 0,\n        messages: 0,\n        sales: 0,\n        revenue: 0,\n        spend: 0,\n        dailyBudget: 0,\n      });\n    }\n    const row = map.get(key);\n    row.sales += 1;\n    row.revenue += Number(sale.amount || 0);\n  }\n\n  return [...map.values()].map((row) => {\n    const cpa = row.sales > 0 ? row.spend / row.sales : 0;\n    const roas = row.spend > 0 ? row.revenue / row.spend : 0;\n    const costPerMessage = row.messages > 0 ? row.spend / row.messages : 0;\n    return {\n      ...row,\n      cpa,\n      roas,\n      costPerMessage,\n      recommendation: recommend(row, cpa, roas),\n    };\n  });\n}\n\nfunction recommend(row, cpa, roas) {\n  const rules = state.rules;\n  if (row.messages < Number(rules.minLeads)) return \"hold\";\n  if (row.sales === 0 && row.spend > Number(rules.targetCpa)) return \"pause\";\n  if (row.sales > 0 && (cpa > Number(rules.targetCpa) * 1.35 || roas < Number(rules.minRoas) * 0.65)) return \"reduce\";\n  if (row.sales > 0 && cpa <= Number(rules.targetCpa) && roas >= Number(rules.minRoas)) return \"scale\";\n  return \"hold\";\n}\n\nfunction recommendationLabel(value) {\n  return {\n    scale: \"Subir\",\n    hold: \"Mantener\",\n    reduce: \"Bajar\",\n    pause: \"Pausar\",\n  }[value];\n}\n\nfunction render() {\n  renderMetrics();\n  renderCrm();\n  renderAdIdOptions();\n  renderPerformance();\n  renderRecentSales();\n  renderSalesTable();\n  renderLeadsTable();\n  renderSpendTable();\n  fillRules();\n}\n\nfunction renderAdIdOptions() {\n  const datalist = document.getElementById(\"adIdOptions\");\n  if (!datalist) return;\n  const seen = new Set();\n  const rows = [];\n  for (const ad of state.ads || []) {\n    const id = normalizeAdId(ad.id || ad.adId);\n    if (!id || seen.has(id)) continue;\n    seen.add(id);\n    rows.push({ id, label: `${ad.name || ad.ad || \"Sin anuncio\"} / ${ad.campaign || \"Sin campaña\"}` });\n  }\n  datalist.innerHTML = rows.map((row) => `<option value=\"${escapeHtml(row.id)}\">${escapeHtml(row.label)}</option>`).join(\"\");\n}\n\nfunction renderMetrics() {\n  const performance = getPerformance();\n  const spend = performance.reduce((sum, item) => sum + item.spend, 0);\n  const messages = performance.reduce((sum, item) => sum + Number(item.messages || 0), 0);\n  const revenue = state.sales.reduce((sum, sale) => sum + Number(sale.amount || 0), 0);\n  const cpa = state.sales.length ? spend / state.sales.length : 0;\n  const roas = spend ? revenue / spend : 0;\n  const costPerMessage = messages ? spend / messages : 0;\n  document.getElementById(\"metricSpend\").textContent = money.format(spend);\n  document.getElementById(\"metricRevenue\").textContent = money.format(revenue);\n  document.getElementById(\"metricMessages\").textContent = numberFormat.format(messages);\n  document.getElementById(\"metricCostPerMessage\").textContent = money.format(costPerMessage);\n  document.getElementById(\"metricRoas\").textContent = `${numberFormat.format(roas)}x`;\n  document.getElementById(\"metricCpa\").textContent = money.format(cpa);\n}\n\nfunction renderPerformance() {\n  const tbody = document.getElementById(\"adsPerformanceTable\");\n  const filter = document.getElementById(\"statusFilter\").value;\n  const rows = getPerformance()\n    .filter((row) => filter === \"all\" || row.recommendation === filter)\n    .sort((a, b) => b.revenue - a.revenue || b.spend - a.spend);\n\n  if (!rows.length) {\n    tbody.innerHTML = `<tr><td colspan=\"10\" class=\"empty\">Todavía no hay datos suficientes.</td></tr>`;\n    return;\n  }\n\n  tbody.innerHTML = rows\n    .map(\n      (row) => `\n        <tr>\n          <td>${escapeHtml(row.ad)}</td>\n          <td>${escapeHtml(row.campaign)}</td>\n          <td>${money.format(row.spend)}</td>\n          <td>${numberFormat.format(row.messages || 0)}</td>\n          <td>${row.sales}</td>\n          <td>${money.format(row.revenue)}</td>\n          <td>${row.messages ? money.format(row.costPerMessage) : \"Sin mensajes\"}</td>\n          <td>${row.sales ? money.format(row.cpa) : \"Sin ventas\"}</td>\n          <td>${row.spend ? `${numberFormat.format(row.roas)}x` : \"0.00x\"}</td>\n          <td><span class=\"badge ${row.recommendation}\">${recommendationLabel(row.recommendation)}</span></td>\n        </tr>\n      `,\n    )\n    .join(\"\");\n}\n\nfunction renderRecentSales() {\n  const container = document.getElementById(\"recentSales\");\n  const rows = [...state.sales].sort((a, b) => new Date(b.date) - new Date(a.date)).slice(0, 6);\n  if (!rows.length) {\n    container.innerHTML = `<div class=\"empty\">Aquí aparecerán las ventas recientes.</div>`;\n    return;\n  }\n\n  container.innerHTML = rows\n    .map((sale) => {\n      const attribution = getSaleAttribution(sale);\n      return `\n        <div class=\"activity-item\">\n          <strong>${escapeHtml(getSaleProducts(sale).join(\", \"))} · ${money.format(Number(sale.amount || 0))}</strong>\n          <span>${escapeHtml(sale.phone)} · ${attribution ? escapeHtml(attribution.ad) : \"Sin atribución\"}</span>\n        </div>\n      `;\n    })\n    .join(\"\");\n}\n\nfunction renderSalesTable() {\n  const tbody = document.getElementById(\"salesTable\");\n  if (!state.sales.length) {\n    tbody.innerHTML = `<tr><td colspan=\"7\" class=\"empty\">Registra la primera venta para empezar.</td></tr>`;\n    return;\n  }\n\n  tbody.innerHTML = [...state.sales]\n    .sort((a, b) => new Date(b.date) - new Date(a.date))\n    .map((sale) => {\n      const attribution = getSaleAttribution(sale);\n      const saleAdId = normalizeAdId(sale.adId);\n      return `\n        <tr>\n          <td>${escapeHtml(sale.date)}</td>\n          <td>${escapeHtml(sale.phone)}</td>\n          <td>${escapeHtml(getSaleProducts(sale).join(\", \"))}</td>\n          <td>${money.format(Number(sale.amount || 0))}</td>\n          <td>${saleAdId ? escapeHtml(saleAdId) : \"Sin ID\"}</td>\n          <td>${attribution ? `${escapeHtml(attribution.ad)} / ${escapeHtml(attribution.campaign)}` : \"Sin coincidencia\"}</td>\n          <td>\n            <div class=\"table-actions\">\n              <button class=\"secondary-button compact\" data-edit-sale-ad=\"${sale.id}\" type=\"button\">Editar ID</button>\n              <button class=\"danger-button compact\" data-delete=\"sales\" data-id=\"${sale.id}\" type=\"button\">Eliminar</button>\n            </div>\n          </td>\n        </tr>\n      `;\n    })\n    .join(\"\");\n}\n\nfunction renderLeadsTable() {\n  const tbody = document.getElementById(\"leadsTable\");\n  if (!state.leads.length) {\n    tbody.innerHTML = `<tr><td colspan=\"6\" class=\"empty\">Aquí aparecerán contactos con número cuando el webhook de WhatsApp entregue mensajes reales con referencia del anuncio.</td></tr>`;\n    return;\n  }\n\n  tbody.innerHTML = [...state.leads]\n    .sort((a, b) => new Date(b.date) - new Date(a.date))\n    .map(\n      (lead) => `\n        <tr>\n          <td>${escapeHtml(lead.date)}</td>\n          <td>${escapeHtml(lead.phone)}</td>\n          <td>${escapeHtml(lead.campaign)}</td>\n          <td>${escapeHtml(lead.ad)}</td>\n          <td>${escapeHtml(lead.adId || \"\")}</td>\n          <td><button class=\"danger-button\" data-delete=\"leads\" data-id=\"${lead.id}\" type=\"button\">Eliminar</button></td>\n        </tr>\n      `,\n    )\n    .join(\"\");\n}\n\nfunction renderSpendTable() {\n  const tbody = document.getElementById(\"spendTable\");\n  if (!state.spend.length) {\n    tbody.innerHTML = `<tr><td colspan=\"7\" class=\"empty\">Los anuncios activos aparecerán aquí cuando conectemos Meta Ads API.</td></tr>`;\n    return;\n  }\n\n  tbody.innerHTML = [...state.spend]\n    .sort((a, b) => new Date(b.date) - new Date(a.date))\n    .map(\n      (spend) => `\n        <tr>\n          <td>${escapeHtml(spend.date)}</td>\n          <td>${escapeHtml(spend.campaign)}</td>\n          <td>${escapeHtml(spend.ad)}</td>\n          <td>${escapeHtml(spend.adId || \"\")}</td>\n          <td>${money.format(Number(spend.spend || 0))}</td>\n          <td>${spend.dailyBudget ? money.format(Number(spend.dailyBudget || 0)) : \"\"}</td>\n          <td><button class=\"danger-button\" data-delete=\"spend\" data-id=\"${spend.id}\" type=\"button\">Eliminar</button></td>\n        </tr>\n      `,\n    )\n    .join(\"\");\n}\n\nfunction fillRules() {\n  const form = document.getElementById(\"rulesForm\");\n  form.elements.targetCpa.value = state.rules.targetCpa;\n  form.elements.minRoas.value = state.rules.minRoas;\n  form.elements.minLeads.value = state.rules.minLeads;\n}\n\nfunction setView(view) {\n  document.querySelectorAll(\".nav-item\").forEach((button) => {\n    button.classList.toggle(\"active\", button.dataset.view === view);\n  });\n  document.querySelectorAll(\".view\").forEach((section) => {\n    section.classList.toggle(\"active\", section.id === `${view}View`);\n  });\n  document.getElementById(\"viewTitle\").textContent = {\n    dashboard: \"Panel\",\n    crm: \"CRM\",\n    sales: \"Ventas\",\n    leads: \"Leads\",\n    ads: \"Anuncios\",\n    settings: \"Datos\",\n  }[view];\n}\n\nfunction getChannelLabel(channel) {\n  return {\n    whatsapp: \"WhatsApp\",\n    messenger: \"Messenger\",\n    instagram: \"Instagram\",\n  }[channel] || channel;\n}\n\nfunction getConversationRows() {\n  const filter = document.getElementById(\"crmChannelFilter\")?.value || \"all\";\n  return [...(state.conversations || [])]\n    .filter((conversation) => filter === \"all\" || conversation.channel === filter)\n    .sort((a, b) => new Date(b.lastAt || 0) - new Date(a.lastAt || 0));\n}\n\nfunction getConversationLead(conversation) {\n  if (conversation.channel !== \"whatsapp\" || !conversation.phone) return null;\n  return findLeadForPhone(conversation.phone);\n}\n\nfunction renderCrm() {\n  const list = document.getElementById(\"conversationList\");\n  const thread = document.getElementById(\"messageThread\");\n  const header = document.getElementById(\"threadHeader\");\n  if (!list || !thread || !header) return;\n\n  const conversations = getConversationRows();\n  if (!activeConversationId && conversations.length) activeConversationId = conversations[0].id;\n  if (activeConversationId && !conversations.some((item) => item.id === activeConversationId)) {\n    activeConversationId = conversations[0]?.id || \"\";\n  }\n\n  if (!conversations.length) {\n    list.innerHTML = `<div class=\"empty\">Aquí aparecerán las conversaciones 1 a 1 nuevas que entregue WhatsApp.</div>`;\n  } else {\n    list.innerHTML = conversations\n      .map((conversation) => {\n        const lead = getConversationLead(conversation);\n        return `\n          <button class=\"conversation-item ${conversation.id === activeConversationId ? \"active\" : \"\"}\" data-conversation-id=\"${escapeHtml(conversation.id)}\" type=\"button\">\n            <span class=\"channel-pill ${escapeHtml(conversation.channel)}\">${getChannelLabel(conversation.channel)}</span>\n            <strong>${escapeHtml(conversation.name || conversation.phone || conversation.contactId)}</strong>\n            <small>${escapeHtml(conversation.lastMessage || \"\")}</small>\n            ${lead ? `<small class=\"conversation-attribution\">${escapeHtml(lead.ad || lead.campaign || \"Anuncio atribuido\")}</small>` : \"\"}\n          </button>\n        `;\n      })\n      .join(\"\");\n  }\n\n  const active = conversations.find((conversation) => conversation.id === activeConversationId);\n  if (!active) {\n    header.innerHTML = `\n      <div>\n        <h2>Selecciona una conversación</h2>\n        <p>Los mensajes nuevos aparecerán aquí cuando llegue el webhook.</p>\n      </div>\n    `;\n    thread.innerHTML = `<div class=\"empty\">Sin conversación seleccionada.</div>`;\n    document.getElementById(\"replyForm\").classList.add(\"disabled\");\n    return;\n  }\n\n  document.getElementById(\"replyForm\").classList.remove(\"disabled\");\n  const activeLead = getConversationLead(active);\n  header.innerHTML = `\n    <div>\n      <h2>${escapeHtml(active.name || active.phone || active.contactId)}</h2>\n      <p>${getChannelLabel(active.channel)}${active.phone ? ` · ${escapeHtml(active.phone)}` : \"\"}${activeLead ? ` · ${escapeHtml(activeLead.ad || activeLead.campaign)}` : \"\"}</p>\n    </div>\n  `;\n\n  const messages = [...(state.messages || [])]\n    .filter((message) => message.conversationId === activeConversationId)\n    .sort((a, b) => new Date(a.at || 0) - new Date(b.at || 0));\n\n  thread.innerHTML = messages.length\n    ? messages\n        .map(\n          (message) => `\n            <div class=\"message-bubble ${message.direction === \"outbound\" ? \"outbound\" : \"inbound\"}\">\n              <p>${escapeHtml(message.text || \"\")}</p>\n              ${message.attachments?.length ? `<small>${escapeHtml(message.attachments.map((item) => item.type).join(\", \"))}</small>` : \"\"}\n              <span>${new Date(message.at || Date.now()).toLocaleString(\"es-MX\", { dateStyle: \"short\", timeStyle: \"short\" })}</span>\n            </div>\n          `,\n        )\n        .join(\"\")\n    : `<div class=\"empty\">Todavía no hay mensajes guardados.</div>`;\n  thread.scrollTop = thread.scrollHeight;\n}\n\nasync function handleSaleSubmit(event) {\n  event.preventDefault();\n  const form = event.currentTarget;\n  const data = Object.fromEntries(new FormData(form));\n  const products = new FormData(form).getAll(\"products\");\n  if (!products.length) {\n    toast(\"Selecciona al menos un producto\");\n    return;\n  }\n  const sale = {\n    id: uid(\"sale\"),\n    phone: normalizePhone(data.phone),\n    products,\n    product: products.join(\", \"),\n    amount: parseMoney(data.amount),\n    date: data.date || today(),\n  };\n\n  applyManualAdAttribution(sale, data.adId);\n  await saveSale(sale, \"Venta registrada\");\n  form.reset();\n  form.elements.date.value = today();\n}\n\nfunction applyManualAdAttribution(sale, adIdInput) {\n  const adId = normalizeAdId(adIdInput);\n  const matchedAd = findAdById(adId);\n  sale.adId = adId;\n  sale.campaign = adId ? matchedAd?.campaign || sale.campaign || \"\" : \"\";\n  sale.adset = adId ? matchedAd?.adset || sale.adset || \"\" : \"\";\n  sale.ad = adId ? adName(matchedAd) || sale.ad || \"\" : \"\";\n  sale.attributionSource = adId ? \"manual_ad_id\" : \"\";\n  return sale;\n}\n\nasync function saveSale(sale, message) {\n  try {\n    if (serverAvailable) {\n      const remoteState = await api(\"/api/sales\", { method: \"POST\", body: JSON.stringify(sale) });\n      applyRemoteState(remoteState);\n    } else {\n      const index = state.sales.findIndex((item) => item.id === sale.id);\n      if (index >= 0) state.sales[index] = { ...state.sales[index], ...sale };\n      else state.sales.push(sale);\n      saveState();\n    }\n    render();\n    toast(message);\n  } catch (error) {\n    toast(error.message);\n  }\n}\n\nasync function editSaleAdId(saleId) {\n  const sale = state.sales.find((item) => item.id === saleId);\n  if (!sale) return;\n  const current = normalizeAdId(sale.adId);\n  const next = prompt(\"Pega el ID del anuncio que aparece en Business Suite. Déjalo vacío para quitarlo.\", current);\n  if (next === null) return;\n  const updated = applyManualAdAttribution({ ...sale }, next);\n  await saveSale(updated, updated.adId ? \"ID de anuncio guardado\" : \"ID de anuncio quitado\");\n}\n\nfunction applyRemoteState(remoteState) {\n  state.conversations = remoteState.conversations || state.conversations;\n  state.messages = remoteState.messages || state.messages;\n  state.sales = remoteState.sales || state.sales;\n  state.leads = remoteState.leads || state.leads;\n  state.spend = remoteState.spend || state.spend;\n  state.ads = remoteState.ads || state.ads;\n  state.rules = remoteState.rules || state.rules;\n  saveState();\n}\n\nfunction persistAndRender(message) {\n  saveState();\n  render();\n  toast(message);\n}\n\nfunction toast(message) {\n  const element = document.getElementById(\"toast\");\n  element.textContent = message;\n  element.classList.add(\"show\");\n  clearTimeout(toast.timer);\n  toast.timer = setTimeout(() => element.classList.remove(\"show\"), 2200);\n}\n\nfunction escapeHtml(value) {\n  return String(value ?? \"\")\n    .replaceAll(\"&\", \"&amp;\")\n    .replaceAll(\"<\", \"&lt;\")\n    .replaceAll(\">\", \"&gt;\")\n    .replaceAll('\"', \"&quot;\")\n    .replaceAll(\"'\", \"&#039;\");\n}\n\nfunction toCsv(rows, columns) {\n  const header = columns.join(\",\");\n  const body = rows\n    .map((row) =>\n      columns\n        .map((column) => {\n          const value = row[column] ?? \"\";\n          return `\"${String(value).replaceAll('\"', '\"\"')}\"`;\n        })\n        .join(\",\"),\n    )\n    .join(\"\\n\");\n  return `${header}\\n${body}`;\n}\n\nfunction download(filename, text, type = \"text/plain\") {\n  const blob = new Blob([text], { type });\n  const url = URL.createObjectURL(blob);\n  const link = document.createElement(\"a\");\n  link.href = url;\n  link.download = filename;\n  link.click();\n  URL.revokeObjectURL(url);\n}\n\nfunction parseCsv(text) {\n  const rows = [];\n  let current = \"\";\n  let row = [];\n  let quoted = false;\n\n  for (let i = 0; i < text.length; i += 1) {\n    const char = text[i];\n    const next = text[i + 1];\n    if (char === '\"' && quoted && next === '\"') {\n      current += '\"';\n      i += 1;\n    } else if (char === '\"') {\n      quoted = !quoted;\n    } else if (char === \",\" && !quoted) {\n      row.push(current);\n      current = \"\";\n    } else if ((char === \"\\n\" || char === \"\\r\") && !quoted) {\n      if (char === \"\\r\" && next === \"\\n\") i += 1;\n      row.push(current);\n      if (row.some((cell) => cell.trim() !== \"\")) rows.push(row);\n      current = \"\";\n      row = [];\n    } else {\n      current += char;\n    }\n  }\n  row.push(current);\n  if (row.some((cell) => cell.trim() !== \"\")) rows.push(row);\n\n  const [headers = [], ...records] = rows;\n  return records.map((record) =>\n    headers.reduce((item, header, index) => {\n      item[header.trim()] = record[index] ?? \"\";\n      return item;\n    }, {}),\n  );\n}\n\nfunction importCsv() {\n  const input = document.getElementById(\"csvInput\");\n  const type = document.getElementById(\"importType\").value;\n  const file = input.files[0];\n  if (!file) {\n    toast(\"Selecciona un CSV primero\");\n    return;\n  }\n  const reader = new FileReader();\n  reader.onload = async () => {\n    const rows = parseCsv(String(reader.result || \"\"));\n    const normalized = rows.map((row) => normalizeImportedRow(type, row));\n    try {\n      if (serverAvailable) {\n        const remoteState = await api(\"/api/import\", {\n          method: \"POST\",\n          body: JSON.stringify({ type, rows: normalized }),\n        });\n        applyRemoteState(remoteState);\n      } else {\n        state[type].push(...normalized);\n        saveState();\n      }\n      input.value = \"\";\n      render();\n      toast(`Importados ${normalized.length} registros`);\n    } catch (error) {\n      toast(error.message);\n    }\n  };\n  reader.readAsText(file);\n}\n\nfunction normalizeImportedRow(type, row) {\n  if (type === \"sales\") {\n    const sale = {\n      id: uid(\"sale\"),\n      phone: normalizePhone(row.phone),\n      products: String(row.product || \"\")\n        .split(/[|,]/)\n        .map((product) => product.trim())\n        .filter(Boolean),\n      product: row.product || \"\",\n      amount: parseMoney(row.amount),\n      date: row.date || today(),\n    };\n    return applyManualAdAttribution(sale, row.adId || row.ad_id || row.metaAdId);\n  }\n  if (type === \"leads\") {\n    return {\n      id: uid(\"lead\"),\n      phone: normalizePhone(row.phone),\n      campaign: row.campaign || \"\",\n      adset: row.adset || \"\",\n      ad: row.ad || \"\",\n      adId: row.adId || \"\",\n      date: row.date || today(),\n      message: row.message || \"\",\n    };\n  }\n  return {\n    id: uid(\"spend\"),\n    campaign: row.campaign || \"\",\n    ad: row.ad || \"\",\n    adId: row.adId || \"\",\n    spend: parseMoney(row.spend),\n    dailyBudget: parseMoney(row.dailyBudget),\n    date: row.date || today(),\n  };\n}\n\nfunction seedDemoData() {\n  const demoPhone = \"529991234567\";\n  state.leads.push({\n    id: uid(\"lead\"),\n    phone: demoPhone,\n    campaign: \"Mensajes Mayo\",\n    adset: \"Lookalike compradores\",\n    ad: \"Video testimonio 01\",\n    adId: \"demo_ad_01\",\n    date: today(),\n    message: \"Hola, quiero informes\",\n  });\n  state.sales.push({\n    id: uid(\"sale\"),\n    phone: demoPhone,\n    products: [\"Imán\", \"Llavero\"],\n    product: \"Imán, Llavero\",\n    amount: 2500,\n    date: today(),\n    adId: \"demo_ad_01\",\n    ad: \"Video testimonio 01\",\n    campaign: \"Mensajes Mayo\",\n    attributionSource: \"manual_ad_id\",\n  });\n  state.spend.push({\n    id: uid(\"spend\"),\n    campaign: \"Mensajes Mayo\",\n    ad: \"Video testimonio 01\",\n    adId: \"demo_ad_01\",\n    spend: 430,\n    dailyBudget: 300,\n    date: today(),\n  });\n  persistAndRender(\"Datos demo agregados\");\n}\n\ndocument.querySelectorAll(\".nav-item\").forEach((button) => {\n  button.addEventListener(\"click\", () => setView(button.dataset.view));\n});\n\ndocument.querySelectorAll(\"[data-open-sale]\").forEach((button) => {\n  button.addEventListener(\"click\", () => setView(\"sales\"));\n});\n\ndocument.getElementById(\"saleForm\").addEventListener(\"submit\", handleSaleSubmit);\ndocument.getElementById(\"statusFilter\").addEventListener(\"change\", renderPerformance);\ndocument.getElementById(\"syncAds\").addEventListener(\"click\", syncAdsFromMeta);\n\ndocument.addEventListener(\"click\", (event) => {\n  const conversationButton = event.target.closest(\"[data-conversation-id]\");\n  if (conversationButton) {\n    activeConversationId = conversationButton.dataset.conversationId;\n    renderCrm();\n    return;\n  }\n\n  const editSaleButton = event.target.closest(\"[data-edit-sale-ad]\");\n  if (editSaleButton) {\n    editSaleAdId(editSaleButton.dataset.editSaleAd);\n    return;\n  }\n\n  const button = event.target.closest(\"[data-delete]\");\n  if (!button) return;\n  const collection = button.dataset.delete;\n  deleteRecord(collection, button.dataset.id);\n});\n\nasync function deleteRecord(collection, id) {\n  try {\n    if (serverAvailable) {\n      const remoteState = await api(`/api/records/${collection}/${encodeURIComponent(id)}`, { method: \"DELETE\" });\n      applyRemoteState(remoteState);\n    } else {\n      state[collection] = state[collection].filter((item) => item.id !== id);\n      saveState();\n    }\n    render();\n    toast(\"Registro eliminado\");\n  } catch (error) {\n    toast(error.message);\n  }\n}\n\ndocument.getElementById(\"exportJson\").addEventListener(\"click\", () => {\n  download(`ventas-ads-${today()}.json`, JSON.stringify(state, null, 2), \"application/json\");\n});\n\ndocument.getElementById(\"exportSalesCsv\").addEventListener(\"click\", () => {\n  const rows = state.sales.map((sale) => ({ ...sale, product: getSaleProducts(sale).join(\"|\") }));\n  download(`ventas-${today()}.csv`, toCsv(rows, [\"phone\", \"product\", \"amount\", \"date\", \"adId\", \"ad\", \"campaign\"]), \"text/csv\");\n});\n\ndocument.getElementById(\"exportLeadsCsv\").addEventListener(\"click\", () => {\n  download(`leads-${today()}.csv`, toCsv(state.leads, [\"phone\", \"campaign\", \"adset\", \"ad\", \"adId\", \"date\", \"message\"]), \"text/csv\");\n});\n\ndocument.getElementById(\"exportSpendCsv\").addEventListener(\"click\", () => {\n  download(`gasto-${today()}.csv`, toCsv(state.spend, [\"campaign\", \"ad\", \"adId\", \"spend\", \"dailyBudget\", \"date\"]), \"text/csv\");\n});\n\ndocument.getElementById(\"importCsv\").addEventListener(\"click\", importCsv);\ndocument.getElementById(\"crmChannelFilter\").addEventListener(\"change\", () => {\n  activeConversationId = \"\";\n  renderCrm();\n});\n\ndocument.getElementById(\"replyForm\").addEventListener(\"submit\", async (event) => {\n  event.preventDefault();\n  const conversation = (state.conversations || []).find((item) => item.id === activeConversationId);\n  const text = event.currentTarget.elements.text.value.trim();\n  if (!conversation || !text) return;\n  try {\n    const remoteState = await api(\"/api/messages\", {\n      method: \"POST\",\n      body: JSON.stringify({\n        channel: conversation.channel,\n        conversationId: conversation.id,\n        to: conversation.phone || conversation.contactId,\n        phone: conversation.phone,\n        name: conversation.name,\n        text,\n      }),\n    });\n    event.currentTarget.reset();\n    applyRemoteState(remoteState);\n    render();\n    toast(\"Mensaje enviado\");\n  } catch (error) {\n    toast(error.message);\n  }\n});\n\ndocument.getElementById(\"rulesForm\").addEventListener(\"submit\", async (event) => {\n  event.preventDefault();\n  const data = Object.fromEntries(new FormData(event.currentTarget));\n  const rules = {\n    targetCpa: parseMoney(data.targetCpa),\n    minRoas: Number(data.minRoas || 0),\n    minLeads: Number(data.minLeads || 0),\n  };\n  try {\n    if (serverAvailable) {\n      const remoteState = await api(\"/api/rules\", { method: \"POST\", body: JSON.stringify(rules) });\n      applyRemoteState(remoteState);\n    } else {\n      state.rules = rules;\n      saveState();\n    }\n    render();\n    toast(\"Reglas guardadas\");\n  } catch (error) {\n    toast(error.message);\n  }\n});\n\ndocument.getElementById(\"fillSaleExample\").addEventListener(\"click\", () => {\n  const form = document.getElementById(\"saleForm\");\n  form.elements.phone.value = \"+52 999 123 4567\";\n  form.querySelectorAll('input[name=\"products\"]').forEach((input) => {\n    input.checked = [\"Imán\", \"Llavero\"].includes(input.value);\n  });\n  form.elements.amount.value = \"2500\";\n  form.elements.date.value = today();\n  form.elements.adId.value = state.ads?.[0]?.id || \"\";\n});\n\ndocument.getElementById(\"clearDemoData\").addEventListener(\"click\", () => {\n  if (!confirm(\"Esto borrara ventas, leads, gastos y reglas guardadas en este navegador. ¿Quieres continuar?\")) {\n    return;\n  }\n  state = structuredClone(defaultState);\n  persistAndRender(\"Datos limpiados\");\n});\n\ndocument.querySelectorAll('input[type=\"date\"]').forEach((input) => {\n  input.value = today();\n});\n\nrender();\nsaveState();\n\nsyncFromServer().then(render);\nsetInterval(() => {\n  syncFromServer().then(render);\n}, 30000);\n\n</script>\n  </body>\n</html>\n";
